arguments.file_text:
namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Pancakes", Category = "breakfast",
            Ingredients = "2 cups flour, 2 eggs, 1.5 cups milk, 2 tbsp sugar, 1 tsp baking powder, pinch of salt",
            Steps = "1. Mix dry ingredients.\n2. Whisk eggs and milk together.\n3. Combine wet and dry ingredients.\n4. Cook on a greased griddle until bubbles form, then flip.",
            AverageRating = 4.5, RatingCount = 12
        },
        new Recipe
        {
            Id = 2, Title = "Avocado Toast", Category = "breakfast",
            Ingredients = "2 slices sourdough bread, 1 ripe avocado, salt, pepper, red pepper flakes, lemon juice",
            Steps = "1. Toast the bread until golden.\n2. Mash avocado with lemon juice, salt, and pepper.\n3. Spread on toast and sprinkle with red pepper flakes.",
            AverageRating = 4.2, RatingCount = 8
        },
        new Recipe
        {
            Id = 3, Title = "Spaghetti Bolognese", Category = "dinner",
            Ingredients = "400g spaghetti, 500g ground beef, 1 onion, 2 cloves garlic, 400g canned tomatoes, 2 tbsp tomato paste, olive oil, basil, salt, pepper",
            Steps = "1. Cook spaghetti according to package directions.\n2. Sauté onion and garlic in olive oil.\n3. Add ground beef and brown.\n4. Stir in tomatoes and tomato paste, simmer 20 min.\n5. Season and serve over pasta with fresh basil.",
            AverageRating = 4.8, RatingCount = 25
        },
        new Recipe
        {
            Id = 4, Title = "Grilled Salmon", Category = "dinner",
            Ingredients = "4 salmon fillets, 2 tbsp olive oil, 1 lemon, 2 cloves garlic, fresh dill, salt, pepper",
            Steps = "1. Mix olive oil, lemon juice, minced garlic, salt, and pepper.\n2. Marinate salmon for 15 minutes.\n3. Grill on medium-high heat for 4-5 minutes per side.\n4. Garnish with fresh dill.",
            AverageRating = 4.6, RatingCount = 15
        },
        new Recipe
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "desserts",
            Ingredients = "200g dark chocolate, 100g butter, 3 eggs, 100g sugar, 50g flour",
            Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs and sugar until fluffy.\n3. Fold in chocolate mixture and flour.\n4. Pour into greased ramekins.\n5. Bake at 200°C for 12 minutes. Center should be gooey.",
            AverageRating = 4.9, RatingCount = 30
        },
        new Recipe
        {
            Id = 6, Title = "Tiramisu", Category = "desserts",
            Ingredients = "500g mascarpone, 4 eggs, 100g sugar, 300ml strong espresso, 2 tbsp coffee liqueur, ladyfinger biscuits, cocoa powder",
            Steps = "1. Separate eggs. Beat yolks with sugar until pale.\n2. Fold in mascarpone.\n3. Whip egg whites to stiff peaks and fold in.\n4. Dip ladyfingers in espresso mixed with liqueur.\n5. Layer biscuits and cream. Refrigerate 4 hours.\n6. Dust with cocoa before serving.",
            AverageRating = 4.7, RatingCount = 20
        }
    };

    public List<Recipe> GetByCategory(string category)
        => _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public List<string> GetCategories()
        => _recipes.Select(r => r.Category).Distinct().ToList();

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is null) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount + stars;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round(totalStars / recipe.RatingCount, 1);
    }
}

