# Star Rating interactive component
cat > Components/Shared/StarRating.razor << 'EOF'
@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="d-inline-block">
    <span class="me-2">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span role="button" style="cursor:pointer; font-size:1.5rem; color:@(star <= SelectedRating ? "#ffc107" : "#ccc")"
                  @onclick="() => Rate(star)">★</span>
        }
    </span>
    <span class="text-muted">@CurrentRating / 5 (@RatingCount ratings)</span>
    @if (Submitted)
    {
        <span class="text-success ms-2">✓ Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentRating { get; set; }
    [Parameter] public int RatingCount { get; set; }

    private int SelectedRating { get; set; }
    private bool Submitted { get; set; }

    private void Rate(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        Submitted = true;
    }
}
EOF

